TriggerOraclev10g.body:
DECLARE    
    vro_agenda_pendiente tkr_agenda_pendiente%ROWTYPE;
BEGIN
    IF :new.id IS NULL
    THEN
        :new.id := tkr_horarios_doctor_seq.NEXTVAL;
        :new.fecha_creacion := f_fecha_actual;
    END IF;
    IF :new.fecha_inicio IS NULL
    THEN
        :new.fecha_inicio := (f_fecha_actual - 1);
    END IF;
    IF pkgca_tkr_agenda_pendiente.f_existe_profesional_pend(:new.id_usuario) = 0 THEN
        vro_agenda_pendiente.id := tkr_agenda_pendiente_seq.nextval;
        vro_agenda_pendiente.id_profesional := :new.id_usuario;
        vro_agenda_pendiente.fecha_registro := f_fecha_actual;
        vro_agenda_pendiente.procesado := 0;
        pkgtkr_agenda_pendiente_dao.p_insertar(vro_agenda_pendiente);
    END IF;
END;
